        while left < right and vowels_list[left] not in vowels:
            left += 1
        while left < right and vowels_list[right] not in vowels:
            right -= 1

        if left < right:
            vowels_list[left], vowels_list[right] = vowels_list[right], vowels_list[left]
            left += 1
            right -= 1

    return ''.join(vowels_list)

def zero_count(arr):
    zeroes = 0
    non_zeroes = 0
    for num in arr:
        if num == 0:
            zeroes += 1
        else:
            non_zeroes += 1
    if non_zeroes == 0:
        return 0
    return zeroes / non_zeroes

import math

def circle_circumference(radius):
    return 2 * math.pi * radius

def pancake_sort(arr):
    n = len(arr)
    for i in range(n, 1, -1):
        # Find the index of the maximum element in the unsorted portion
        max_idx = i - 1
        for j in range(i - 1, -1, -1):
            if arr[j] > arr[max_idx]:
                max_idx = j

        # If the maximum element is not at the correct position
        if max_idx != i - 1:
            # If the maximum element is not at the top, flip it to the top
            if max_idx != 0:
                flip(arr, max_idx)
            # Flip the maximum element to its correct position
            flip(arr, i - 1)

    return arr

def flip(arr, k):
    # Flip the first k+1 elements
    arr = arr[:k+1][::-1] + arr[k+1:]
    return arr

def count_samepair(list1, list2, list3):
    count = 0
    for i in range(min(len(list1), len(list2), len(list3))):
        if list1[i] == list2[i] == list3[i]:
            count += 1
    return count

def max_Abs_Diff(arr):
    if len(arr) < 2:
        return 0
    return max(arr) - min(arr)

def find_solution(a, b, n):
    def extended_gcd(a, b):
        if b == 0:
            return a, 1, 0
        else:
            g, x1, y1 = extended_gcd(b, a % b)
            x = y1
            y = x1 - (a // b) * y1
            return g, x, y

    if a == 0 and b == 0:
        return None if n != 0 else (0, 0)

    gcd, x, y = extended_gcd(a, b)

    if n % gcd != 0:
        return None

    x *= n // gcd
    y *= n // gcd

    return (x, y)

def sum_series(n):
    total = 0
    for i in range(n // 2 + 1):
        total += n - 2 * i
    return total

def are_equivalent(n1, n2):
    def sum_divisors(num):
        if num <= 0:
            return 0
        total = 1
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    return sum_divisors(n1) == sum_divisors(n2)

def count_char_position(s):
    count = 0
    for i, char in enumerate(s):
        char_lower = char.lower()
        if 'a' <= char_lower <= 'z':
            char_position = ord(char_lower) - ord('a')
            if char_position == i:
                count += 1
    return count

def find_even_pair(nums):
    odd_count = 0
    even_count = 0

    for num in nums:
        if num % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    odd_pairs = odd_count * (odd_count - 1) // 2
    even_pairs = even_count * (even_count - 1) // 2

    return odd_pairs + even_pairs

def check_type(t):
    if len(t) == 0:
        return True
    first_type = type(t[0])
    return all(type(x) == first_type for x in t)
